+  return await withCdpSocket(wsUrl, async (send) => {
+    const created = (await send("Target.createTarget", { url: opts.url })) as {
+      targetId?: string;
+    };
+    const targetId = String(created?.targetId ?? "").trim();
+    if (!targetId) {
