+  const page = await getPageForTargetId(opts);
+  const state = ensurePageState(page);
+  if (!opts.level) {
+    return [...state.console];
+  }
+  const min = consolePriority(opts.level);
+  return state.console.filter((msg) => consolePriority(msg.type) >= min);
