+          }
+          default: {
+            return jsonError(res, 400, "unsupported kind");
+          }
+        }
+      },
+    });
+  });
+
+  registerBrowserAgentActHookRoutes(app, ctx);
+  registerBrowserAgentActDownloadRoutes(app, ctx);
