+type CdpTarget = {
+  id?: string;
+  title?: string;
+  url?: string;
+  webSocketDebuggerUrl?: string;
+  type?: string;
+};
+
+export function createProfileTabOps({
+  profile,
+  state,
+  getProfileState,
