+      cdpUrl: profile.cdpUrl,
+      url,
+      ...ssrfPolicyOpts,
+    })
+      .then((r) => r.targetId)
+      .catch(() => null);
+
+    if (createdViaCdp) {
+      const profileState = getProfileState();
+      profileState.lastTargetId = createdViaCdp;
